// Fake Fetch to simulate backend with smart backend fallback
const originalFetch = window.fetch;
window.fetch = async function(url, options) {
  // If it's a relative API request, let's try to query the real backend first
  if (url.startsWith('/api/')) {
    try {
      // Avoid infinite loop by calling originalFetch
      const response = await originalFetch(url, options);
      // If the response is not a 404, we use the real backend response
      if (response.status !== 404) {
        return response;
      }
    } catch (e) {
      // Server is offline, fallback to mock data
      console.log('Backend server not responding, using local mock data.', e);
    }
  }

  const mockResponse = (data) => ({
    ok: true,
    status: 200,
    json: async () => data,
    text: async () => JSON.stringify(data)
  });

  if (url === '/api/team') return mockResponse(window.siteData.team);
  if (url === '/api/site-images') return mockResponse(window.siteData.siteImages);
  if (url === '/api/services') return mockResponse(window.siteData.services);
  if (url === '/api/home-services') return mockResponse(window.siteData.homeServices);
  if (url === '/api/promotion') return mockResponse(window.siteData.promotion || { is_active: 0 });
  if (url === '/api/testimonials') return mockResponse(window.siteData.testimonials);
  if (url === '/api/portfolio') return mockResponse(window.siteData.projects);
  if (url.startsWith('/api/portfolio/')) {
    const id = url.split('/').pop();
    const project = window.siteData.projects.find(p => p.id == id);
    return mockResponse(project || {});
  }
  if (url === '/api/settings') return mockResponse({});
  if (url === '/api/contact') {
    alert('Thank you! (Note: The backend is disabled, so this is a simulation)');
    return mockResponse({ success: true });
  }

  return originalFetch(url, options);
};
